const cfg = $('Configuracoes').first().json;
const responseLinks = $input.first().json;
const stagesResponse = $('Buscar_Etapas_Board').first().json;

const links = Array.isArray(responseLinks?.data) ? responseLinks.data : [];
const stages = Array.isArray(stagesResponse?.data) ? stagesResponse.data : [];

const normalize = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

const followUpConfigured = String(cfg.StageFollowUpLabel || 'Follow-up');
const finalizadoConfigured = String(cfg.StageFinalizadoLabel || 'Finalizado');
const dateStrategy = String(cfg.EstrategiaDataMensagem || 'fallback_updated_at');

const followUpStage = stages.find((s) => {
  const label = normalize(s.label);
  return label === normalize(followUpConfigured)
    || label === 'follow-up'
    || label === 'follow up'
    || label === 'followup'
    || label.includes('follow');
});

const finalizadoStage = stages.find((s) => {
  const label = normalize(s.label);
  return label === normalize(finalizadoConfigured) || label.startsWith('finaliz');
});

if (!followUpStage) {
  throw new Error('Etapa de Follow-up nao encontrada no board. Ajuste StageFollowUpLabel em Configuracoes.');
}

if (!finalizadoStage) {
  throw new Error('Etapa Finalizado nao encontrada no board. Ajuste StageFinalizadoLabel em Configuracoes.');
}

const stageLabelById = {};
for (const stage of stages) {
  if (stage?.id) stageLabelById[stage.id] = stage.label || '';
}

const nowMs = Date.now();
const waitDays = Number(cfg.DiasSemMensagem || 25);
const ignoreDaysRule = Boolean(cfg.IgnorarRegraDias);
const cutoffMs = nowMs - (waitDays * 24 * 60 * 60 * 1000);

const parseDate = (raw, field) => {
  if (!raw) return null;
  const ms = Date.parse(raw);
  if (!Number.isFinite(ms)) return null;
  return {
    sourceDateMs: ms,
    sourceDateAt: new Date(ms).toISOString(),
    sourceDateField: field,
  };
};

const getDateCandidate = (link) => {
  const lastMessage = parseDate(link.lastMessageAt || link.last_message_at || null, 'lastMessageAt');
  if (lastMessage) return lastMessage;

  // Estrategias de fallback (somente se configurado explicitamente)
  if (dateStrategy === 'fallback_updated_at') {
    const updated = parseDate(link.updatedAt || link.updated_at || null, 'updatedAt');
    if (updated) return updated;
  }

  if (dateStrategy === 'fallback_created_at') {
    const created = parseDate(link.createdAt || link.created_at || null, 'createdAt');
    if (created) return created;
  }

  return null;
};

const latestByDeal = new Map();
let linksWithLastMessageAt = 0;

for (const link of links) {
  const dealId = link.dealId || link.deal_id || null;
  if (!dealId) continue;

  if (link.lastMessageAt || link.last_message_at) linksWithLastMessageAt += 1;

  const candidateDate = getDateCandidate(link);
  if (!candidateDate) continue;

  const existing = latestByDeal.get(dealId);
  if (!existing || candidateDate.sourceDateMs > existing.sourceDateMs) {
    latestByDeal.set(dealId, {
      dealId,
      sourceDateMs: candidateDate.sourceDateMs,
      sourceDateAt: candidateDate.sourceDateAt,
      sourceDateField: candidateDate.sourceDateField,
      diasSemMensagem: Math.floor((nowMs - candidateDate.sourceDateMs) / (24 * 60 * 60 * 1000)),
      status: link.status || 'unknown',
      contactId: link.contactId || link.contact_id || '',
      lastMessagePreview: String(link.lastMessagePreview || link.last_message_preview || '').trim(),
    });
  }
}

if (dateStrategy === 'strict_last_message' && links.length > 0 && linksWithLastMessageAt === 0) {
  throw new Error('Nenhum conversation-link possui lastMessageAt. Altere EstrategiaDataMensagem para fallback_updated_at ou preencha last_message_at na origem.');
}

const output = [];
for (const candidate of latestByDeal.values()) {
  if (!ignoreDaysRule && candidate.sourceDateMs > cutoffMs) continue;

  output.push({
    json: {
      ...candidate,
      lastMessageAt: candidate.sourceDateAt,
      followUpLabel: followUpStage.label,
      finalizadoLabel: finalizadoStage.label,
      stageLabelById,
      waitDays,
      ignoreDaysRule,
      dateStrategy,
    }
  });
}

return output;

const candidates = $('Preparar_Candidatos').all();

const asText = (value) => {
  if (value === null || value === undefined) return '';
  return String(value).trim();
};

const summaryFields = [
  ['ai_summary', (deal) => deal?.ai_summary],
  ['aiSummary', (deal) => deal?.aiSummary],
  ['summary', (deal) => deal?.summary],
  ['resumo', (deal) => deal?.resumo],
  ['resumo_conversa', (deal) => deal?.resumo_conversa],
  ['conversation_summary', (deal) => deal?.conversation_summary],
  ['conversationSummary', (deal) => deal?.conversationSummary],
  ['metadata.ai_summary', (deal) => deal?.metadata?.ai_summary],
  ['metadata.aiSummary', (deal) => deal?.metadata?.aiSummary],
];

const output = [];

for (let index = 0; index < items.length; index += 1) {
  const candidate = candidates[index]?.json || {};
  const response = items[index]?.json || {};

  const responseData = response?.data;
  const deal = (
    responseData && typeof responseData === 'object' && !Array.isArray(responseData)
      ? responseData
      : response && typeof response === 'object' && !Array.isArray(response)
        ? response
        : null
  ) || {};

  let resumoConversa = '';
  let summarySource = 'none';

  for (const [fieldName, getter] of summaryFields) {
    const value = asText(getter(deal));
    if (!value) continue;
    resumoConversa = value;
    summarySource = fieldName;
    break;
  }

  const selectedStageId = asText(deal.stage_id || deal.stageId);

  output.push({
    json: {
      dealId: candidate.dealId || asText(deal.id),
      dealTitle: asText(deal.title),
      currentStageId: selectedStageId,
      currentStageLabel: asText(candidate.stageLabelById?.[selectedStageId]),
      resumoConversa,
      followUpLabel: candidate.followUpLabel || '',
      finalizadoLabel: candidate.finalizadoLabel || '',
      diasSemMensagem: candidate.diasSemMensagem || 0,
      lastMessageAt: candidate.lastMessageAt || '',
      contactId: candidate.contactId || '',
      summarySource,
      summaryLength: resumoConversa.length,
      apiDealId: asText(deal.id),
    }
  });
}

return output;

const normalize = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[̀-ͯ]/g, '')
  .toLowerCase()
  .trim();

const output = [];

for (const item of items) {
  const stageNorm = normalize(item.json.currentStageLabel);
  if (stageNorm.startsWith('nova intera')) continue;

  const resumo = String(item.json.resumoConversa || '').trim();
  if (!resumo) continue;

  output.push({
    json: {
      ...item.json,
      resumoConversa: resumo,
      semResumoCRM: false,
    }
  });
}

if (items.length > 0 && output.length === 0) {
  const sample = items.slice(0, 5).map((item) => ({
    dealId: item.json.dealId,
    apiDealId: item.json.apiDealId || '',
    currentStageLabel: item.json.currentStageLabel || '',
    summarySource: item.json.summarySource || 'none',
    summaryLength: item.json.summaryLength || 0,
  }));

  throw new Error('Nenhum deal com resumo apos filtros. Amostra: ' + JSON.stringify(sample));
}

return output;

const normalize = (value) => String(value || '')
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .toLowerCase()
  .trim();

return items.map((item) => {
  const data = item.json;
  const analysis = data.analysis || {};

  const sentiment = normalize(analysis.sentimento);
  const isPositive = sentiment === 'positivo';
  const clienteGanho = Boolean(analysis.cliente_ganho);
  const semContexto = Boolean(analysis.sem_contexto_nova_conversa);

  const currentStageNorm = normalize(data.currentStageLabel);
  const followNorm = normalize(data.followUpLabel);

  let action = 'none';
  let targetStageLabel = '';
  let decisionReason = 'Regra nao atendida';

  if (currentStageNorm.startsWith('finaliz')) {
    decisionReason = 'Deal ja esta em Finalizado';
  } else if (isPositive && clienteGanho) {
    if (currentStageNorm === followNorm) {
      decisionReason = 'Deal ja esta em Follow-up';
    } else {
      action = 'move';
      targetStageLabel = data.followUpLabel;
      decisionReason = 'Sentimento positivo com indicacao de cliente ganho';
    }
  } else if (!isPositive && semContexto) {
    action = 'move';
    targetStageLabel = data.finalizadoLabel;
    decisionReason = 'Conversa nao positiva e sem contexto para retomar';
  }

  return {
    json: {
      ...data,
      action,
      targetStageLabel,
      decisionReason
    }
  };
});
